import React from "react";
import "./nav.css";

function Nav() {
  const [isActive, setIsActive] = React.useState(false);
  const handleClick = () => {
    setIsActive((current) => !current);
  };
  return (
    <div
      onClick={handleClick}
      style={{
        display: isActive ? "block" : "",
        display: isActive ? "none" : "",
      }}
      className="gg-menu-grid-o"
    >
      <div className="pushMenu"></div>
    </div>
  );
}

export default Nav;

